                        width = len(line)
                }
        }
        w := &World{Width: width, Height: height, Walls: make([]bool, width*height)}
        for y, line := range lines {
                for x := 0; x < width; x++ {
                        ch := byte('.')
                        if x < len(line) {
                                ch = line[x]
                        }
                        idx := w.Idx(x, y)
                        switch ch {
